import Link from "next/link";
import type { Person } from "../../../platform/admin/data-capture/types";
import { formatDate, getGenerationLabel, getRelationLabel } from "../helpers";
import styles from "../workspace.module.css";

type MemberDirectoryProps = {
  people: Person[];
  selectedPersonId: string;
  onSelectPerson: (personId: string) => void;
  canManageData?: boolean;
};

const getAgeLabel = (dateOfBirth: string | null) => {
  if (!dateOfBirth) {
    return "Age not added";
  }

  const birthDate = new Date(dateOfBirth);
  if (Number.isNaN(birthDate.getTime())) {
    return "Age not added";
  }

  const today = new Date();
  let age = today.getFullYear() - birthDate.getFullYear();
  const monthDiff = today.getMonth() - birthDate.getMonth();
  if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
    age -= 1;
  }

  return `Age ${Math.max(age, 0)}`;
};

export function MemberDirectory({ people, selectedPersonId, onSelectPerson, canManageData = false }: MemberDirectoryProps) {
  return (
    <section className={styles.scard}>
      <div className={styles.scardHeader}>
        <div className={styles.scardTitleWrap}>
          <h2 className={styles.scardTitle}>Member Directory</h2>
          <p className={styles.scardSub}>{people.length} members - browse and open a profile in one click</p>
        </div>
        {canManageData ? (
          <Link href="/platform/admin/data-capture" className={styles.secondaryButton}>
            + Add Member
          </Link>
        ) : null}
      </div>
      <div className={styles.memberGrid}>
        {people.map((person) => (
          <div
            key={person.id}
            className={`${styles.memberCard} ${selectedPersonId === person.id ? styles.memberCardActive : ""}`}
          >
            <div className={styles.memberGeneration}>{getGenerationLabel(person)}</div>
            <div className={styles.memberAvatar}>{person.fullName.slice(0, 1).toUpperCase()}</div>
            <button type="button" className={styles.cardButton} onClick={() => onSelectPerson(person.id)}>
              <strong>{person.fullName}</strong>
              <span>{getRelationLabel(person)}</span>
              <span>{formatDate(person.dateOfBirth)} - {getAgeLabel(person.dateOfBirth)}</span>
            </button>
            <Link className={styles.inlineLink} href={`/family-space/members/${person.id}`}>
              Open profile -&gt;
            </Link>
          </div>
        ))}
      </div>
    </section>
  );
}
