"use client";

import Link from "next/link";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { CSSProperties, PointerEvent as ReactPointerEvent } from "react";
import type { Person, Relationship } from "../../../platform/admin/data-capture/types";
import { buildImmediateFamilyRelations, getGenerationLabel, getRelationLabel } from "../helpers";
import styles from "../workspace.module.css";

type FamilyTreeProps = {
  people: Person[];
  relationships: Relationship[];
  selectedPersonId: string;
  onSelectPerson: (personId: string) => void;
  memberCount?: number;
  relationshipCount?: number;
};

type RelationEdge = {
  toId: string;
  delta: number;
  label: string;
};

type TreeNode = {
  id: string;
  level: number;
  hops: number;
  viaLabel: string;
};

type DragState = {
  pointerId: number;
  startX: number;
  startY: number;
  startPanX: number;
  startPanY: number;
};

const MIN_ZOOM = 0.5;
const MAX_ZOOM = 2;
const ZOOM_STEP = 0.1;

const clamp = (value: number, min: number, max: number) => Math.min(max, Math.max(min, value));

const escapeXml = (value: string) =>
  value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&apos;");

const addEdge = (graph: Map<string, RelationEdge[]>, fromId: string, edge: RelationEdge) => {
  const edges = graph.get(fromId) ?? [];
  const exists = edges.some(
    (current) => current.toId === edge.toId && current.delta === edge.delta && current.label === edge.label,
  );
  if (exists) {
    return;
  }
  edges.push(edge);
  graph.set(fromId, edges);
};

const relationshipKey = (fromId: string, toId: string, relationshipType: string) => `${fromId}|${toId}|${relationshipType}`;

const isSpouseLikeRelationship = (relationshipType: string) =>
  relationshipType === "spouse_of" ||
  relationshipType === "divorced_from" ||
  relationshipType === "separated_from" ||
  relationshipType === "widowed_from";

const toEdgeLabels = (relationshipType: string) => {
  switch (relationshipType) {
    case "parent_of":
      return {
        forward: { delta: 1, label: "Child" },
        reverse: { delta: -1, label: "Parent" },
      };
    case "guardian_of":
      return {
        forward: { delta: 1, label: "Ward" },
        reverse: { delta: -1, label: "Guardian" },
      };
    case "spouse_of":
      return {
        forward: { delta: 0, label: "Spouse" },
        reverse: { delta: 0, label: "Spouse" },
      };
    case "divorced_from":
      return {
        forward: { delta: 0, label: "Divorced" },
        reverse: { delta: 0, label: "Divorced" },
      };
    case "separated_from":
      return {
        forward: { delta: 0, label: "Separated" },
        reverse: { delta: 0, label: "Separated" },
      };
    case "widowed_from":
      return {
        forward: { delta: 0, label: "Past spouse" },
        reverse: { delta: 0, label: "Past spouse" },
      };
    case "sibling_of":
      return {
        forward: { delta: 0, label: "Sibling" },
        reverse: { delta: 0, label: "Sibling" },
      };
    default:
      return {
        forward: { delta: 0, label: "Related" },
        reverse: { delta: 0, label: "Related" },
      };
  }
};

const buildRelationshipGraph = (relationships: Relationship[]) => {
  const graph = new Map<string, RelationEdge[]>();
  const explicitRelationshipKeys = new Set<string>();
  const parentToChildren = new Map<string, Set<string>>();
  const spouseMap = new Map<string, Set<string>>();

  for (const relationship of relationships) {
    const sourceId = relationship.personOne.id;
    const targetId = relationship.personTwo.id;
    const labels = toEdgeLabels(relationship.relationshipType);
    explicitRelationshipKeys.add(relationshipKey(sourceId, targetId, relationship.relationshipType));

    addEdge(graph, sourceId, { toId: targetId, delta: labels.forward.delta, label: labels.forward.label });
    addEdge(graph, targetId, { toId: sourceId, delta: labels.reverse.delta, label: labels.reverse.label });

    if (relationship.relationshipType === "parent_of") {
      const children = parentToChildren.get(sourceId) ?? new Set<string>();
      children.add(targetId);
      parentToChildren.set(sourceId, children);
    }

    if (isSpouseLikeRelationship(relationship.relationshipType)) {
      const sourceSpouses = spouseMap.get(sourceId) ?? new Set<string>();
      sourceSpouses.add(targetId);
      spouseMap.set(sourceId, sourceSpouses);

      const targetSpouses = spouseMap.get(targetId) ?? new Set<string>();
      targetSpouses.add(sourceId);
      spouseMap.set(targetId, targetSpouses);
    }
  }

  // Derived co-parent links:
  // parent_of(A, child) + spouse_like(A, B) => derived parent_of(B, child)
  for (const [parentId, children] of parentToChildren.entries()) {
    const spouses = spouseMap.get(parentId);
    if (!spouses?.size) {
      continue;
    }

    for (const spouseId of spouses) {
      for (const childId of children) {
        const hasExplicitParent =
          explicitRelationshipKeys.has(relationshipKey(spouseId, childId, "parent_of")) ||
          explicitRelationshipKeys.has(relationshipKey(spouseId, childId, "guardian_of"));

        if (hasExplicitParent) {
          continue;
        }

        addEdge(graph, spouseId, { toId: childId, delta: 1, label: "Child (derived)" });
        addEdge(graph, childId, { toId: spouseId, delta: -1, label: "Parent (derived)" });
      }
    }
  }

  return graph;
};

const buildTreeNodes = (
  selectedPersonId: string,
  relationships: Relationship[],
  generationDepth: number,
): Map<string, TreeNode> => {
  const graph = buildRelationshipGraph(relationships);
  const nodes = new Map<string, TreeNode>();
  const queue: TreeNode[] = [{ id: selectedPersonId, level: 0, hops: 0, viaLabel: "Self" }];

  nodes.set(selectedPersonId, queue[0]);

  while (queue.length) {
    const current = queue.shift();
    if (!current) {
      break;
    }

    const edges = graph.get(current.id) ?? [];
    for (const edge of edges) {
      const nextLevel = current.level + edge.delta;
      if (generationDepth > 0 && Math.abs(nextLevel) > generationDepth) {
        continue;
      }

      const nextHops = current.hops + 1;
      const existing = nodes.get(edge.toId);
      const isBetterCandidate =
        !existing ||
        nextHops < existing.hops ||
        (nextHops === existing.hops && Math.abs(nextLevel) < Math.abs(existing.level));

      if (!isBetterCandidate) {
        continue;
      }

      const nextNode = {
        id: edge.toId,
        level: nextLevel,
        hops: nextHops,
        viaLabel: nextHops === 1 ? edge.label : "Derived",
      };
      nodes.set(edge.toId, nextNode);
      queue.push(nextNode);
    }
  }

  return nodes;
};

const rowLabel = (level: number) => {
  if (level < 0) {
    return Math.abs(level) === 1 ? "Parents / Guardians" : `${Math.abs(level)} generations above`;
  }
  if (level === 0) {
    return "Same generation";
  }
  return level === 1 ? "Children / Wards" : `${level} generations below`;
};

const descriptorForNode = (node: TreeNode) => {
  if (node.hops === 1) {
    return node.viaLabel;
  }
  if (node.level < 0) {
    return `${Math.abs(node.level)} generations above`;
  }
  if (node.level > 0) {
    return `${node.level} generations below`;
  }
  return "Same generation";
};

const partnerRoleLabel = (gender: string | null) => {
  const normalized = (gender ?? "").toLowerCase();
  if (normalized === "male") {
    return "Husband";
  }
  if (normalized === "female") {
    return "Wife";
  }
  return "Spouse";
};

export function FamilyTree({
  people,
  relationships,
  selectedPersonId,
  onSelectPerson,
  memberCount,
  relationshipCount,
}: FamilyTreeProps) {
  const [zoom, setZoom] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [exportMessage, setExportMessage] = useState("");
  const [dragState, setDragState] = useState<DragState | null>(null);
  const [pan, setPan] = useState({ x: 24, y: 24 });

  const viewportRef = useRef<HTMLDivElement | null>(null);
  const canvasRef = useRef<HTMLDivElement | null>(null);

  const selectedPerson = people.find((person) => person.id === selectedPersonId) ?? null;
  const peopleById = useMemo(() => new Map(people.map((person) => [person.id, person])), [people]);
  const treeNodes = useMemo(
    () => buildTreeNodes(selectedPersonId, relationships, 0),
    [selectedPersonId, relationships],
  );

  const groupedLevels = useMemo(() => {
    const levels = new Map<number, Array<{ person: Person; node: TreeNode }>>();

    for (const node of treeNodes.values()) {
      const person = peopleById.get(node.id);
      if (!person) {
        continue;
      }
      const levelNodes = levels.get(node.level) ?? [];
      levelNodes.push({ person, node });
      levels.set(node.level, levelNodes);
    }

    for (const levelNodes of levels.values()) {
      levelNodes.sort((left, right) => left.person.fullName.localeCompare(right.person.fullName));
    }

    const above = Array.from(levels.entries())
      .filter(([level]) => level < 0)
      .sort((left, right) => left[0] - right[0]);
    const same = levels.get(0)?.filter((item) => item.person.id !== selectedPersonId) ?? [];
    const below = Array.from(levels.entries())
      .filter(([level]) => level > 0)
      .sort((left, right) => left[0] - right[0]);

    return { above, same, below };
  }, [treeNodes, peopleById, selectedPersonId]);

  const immediate = useMemo(
    () => buildImmediateFamilyRelations(people, relationships, selectedPersonId, selectedPerson?.gender ?? null),
    [people, relationships, selectedPersonId, selectedPerson?.gender],
  );
  const spouseIds = useMemo(() => new Set(immediate.spouses.map((spouse) => spouse.id)), [immediate.spouses]);
  const primarySpouse = useMemo(
    () => immediate.spouses.map((spouse) => peopleById.get(spouse.id)).find((person): person is Person => Boolean(person)) ?? null,
    [immediate.spouses, peopleById],
  );
  const sameGenerationSiblings = useMemo(
    () => groupedLevels.same.filter(({ person }) => !spouseIds.has(person.id)),
    [groupedLevels.same, spouseIds],
  );

  const applyZoomAroundCenter = (nextZoom: number) => {
    const safeZoom = clamp(nextZoom, MIN_ZOOM, MAX_ZOOM);
    const viewport = viewportRef.current;
    if (!viewport) {
      setZoom(safeZoom);
      return;
    }

    setPan((current) => {
      const centerX = viewport.clientWidth / 2;
      const centerY = viewport.clientHeight / 2;
      const worldX = (centerX - current.x) / zoom;
      const worldY = (centerY - current.y) / zoom;
      return {
        x: centerX - worldX * safeZoom,
        y: centerY - worldY * safeZoom,
      };
    });
    setZoom(safeZoom);
  };

  const fitToScreen = useCallback(() => {
    const viewport = viewportRef.current;
    const canvas = canvasRef.current;
    if (!viewport || !canvas) {
      return;
    }

    const padding = 24;
    const widthScale = (viewport.clientWidth - padding * 2) / canvas.offsetWidth;
    const heightScale = (viewport.clientHeight - padding * 2) / canvas.offsetHeight;
    const nextZoom = clamp(Math.min(widthScale, heightScale), MIN_ZOOM, MAX_ZOOM);
    const nextPan = {
      x: (viewport.clientWidth - canvas.offsetWidth * nextZoom) / 2,
      y: (viewport.clientHeight - canvas.offsetHeight * nextZoom) / 2,
    };

    setZoom(nextZoom);
    setPan(nextPan);
  }, []);

  const buildExportSvg = useCallback(() => {
    if (!selectedPerson) {
      return "";
    }

    const cardWidth = 220;
    const cardHeight = 88;
    const colGap = 28;
    const rowGap = 78;
    const margin = 40;

    const rows: Array<{
      title: string;
      items: Array<{ person: Person; descriptor: string; isFocus: boolean }>;
    }> = [];

    for (const [level, nodes] of groupedLevels.above) {
      rows.push({
        title: rowLabel(level),
        items: nodes.map(({ person, node }) => ({ person, descriptor: descriptorForNode(node), isFocus: false })),
      });
    }

    rows.push({
      title: "Selected",
      items: [
        {
          person: selectedPerson,
          descriptor: getRelationLabel(selectedPerson),
          isFocus: true,
        },
      ],
    });

    if (groupedLevels.same.length) {
      rows.push({
        title: rowLabel(0),
        items: groupedLevels.same.map(({ person, node }) => ({ person, descriptor: descriptorForNode(node), isFocus: false })),
      });
    }

    for (const [level, nodes] of groupedLevels.below) {
      rows.push({
        title: rowLabel(level),
        items: nodes.map(({ person, node }) => ({ person, descriptor: descriptorForNode(node), isFocus: false })),
      });
    }

    const maxCols = Math.max(1, ...rows.map((row) => row.items.length));
    const width = margin * 2 + maxCols * cardWidth + (maxCols - 1) * colGap;
    const height = margin * 2 + rows.length * cardHeight + (rows.length - 1) * rowGap;

    const focusRowIndex = rows.findIndex((row) => row.items.some((item) => item.isFocus));
    const rowCenters = rows.map((row, rowIndex) => {
      const rowWidth = row.items.length * cardWidth + Math.max(0, row.items.length - 1) * colGap;
      const startX = (width - rowWidth) / 2;
      const y = margin + rowIndex * (cardHeight + rowGap);
      return { row, rowIndex, startX, y };
    });

    const lineElements: string[] = [];
    const nodeElements: string[] = [];

    for (const rowMeta of rowCenters) {
      const { row, rowIndex, startX, y } = rowMeta;

      nodeElements.push(
        `<text x="${startX}" y="${y - 10}" fill="#6f5a42" font-size="12" font-family="Arial, sans-serif">${escapeXml(row.title)}</text>`,
      );

      row.items.forEach((item, itemIndex) => {
        const x = startX + itemIndex * (cardWidth + colGap);
        const fill = item.isFocus ? "#254a2f" : "#fffaf2";
        const stroke = item.isFocus ? "#1b3824" : "#ddcfbb";
        const nameColor = item.isFocus ? "#fff5df" : "#2c1f0e";
        const metaColor = item.isFocus ? "#d9ebdd" : "#715941";

        nodeElements.push(
          `<rect x="${x}" y="${y}" width="${cardWidth}" height="${cardHeight}" rx="14" ry="14" fill="${fill}" stroke="${stroke}" stroke-width="1.4" />`,
        );
        nodeElements.push(
          `<text x="${x + 14}" y="${y + 34}" fill="${nameColor}" font-size="18" font-weight="700" font-family="Georgia, serif">${escapeXml(item.person.fullName)}</text>`,
        );
        nodeElements.push(
          `<text x="${x + 14}" y="${y + 60}" fill="${metaColor}" font-size="12.5" font-family="Arial, sans-serif">${escapeXml(item.descriptor)}</text>`,
        );

        if (focusRowIndex >= 0 && rowIndex !== focusRowIndex) {
          const focusRow = rowCenters[focusRowIndex];
          const focusX = focusRow.startX + cardWidth / 2;
          const focusY = focusRow.y + cardHeight / 2;
          const targetX = x + cardWidth / 2;
          const targetY = y + cardHeight / 2;
          lineElements.push(
            `<line x1="${focusX}" y1="${focusY}" x2="${targetX}" y2="${targetY}" stroke="#8bb08f" stroke-width="1.2" opacity="0.55" />`,
          );
        }
      });
    }

    return `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
      <rect x="0" y="0" width="${width}" height="${height}" fill="#f8f2e6"/>
      ${lineElements.join("")}
      ${nodeElements.join("")}
    </svg>`;
  }, [groupedLevels.above, groupedLevels.below, groupedLevels.same, selectedPerson]);

  const exportImage = () => {
    const svg = buildExportSvg();
    if (!svg) {
      setExportMessage("Select a member before exporting.");
      return;
    }

    const blob = new Blob([svg], { type: "image/svg+xml;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `kutumbsy-tree-${selectedPerson?.fullName?.replaceAll(" ", "-").toLowerCase() ?? "export"}.svg`;
    link.click();
    URL.revokeObjectURL(url);
    setExportMessage("Tree image exported as SVG.");
  };

  const exportPdf = () => {
    const svg = buildExportSvg();
    if (!svg) {
      setExportMessage("Select a member before exporting.");
      return;
    }

    const popup = window.open("", "_blank", "noopener,noreferrer,width=1280,height=900");
    if (!popup) {
      setExportMessage("Allow pop-ups to export PDF.");
      return;
    }

    popup.document.write(`
      <html>
        <head>
          <title>Kutumbsy Family Tree Export</title>
          <style>
            body { margin: 0; padding: 16px; background: #ffffff; font-family: Arial, sans-serif; }
            .wrap { display: flex; justify-content: center; }
            svg { width: 100%; height: auto; max-width: 1300px; border: 1px solid #ddd; }
            @page { size: landscape; margin: 10mm; }
          </style>
        </head>
        <body>
          <div class="wrap">${svg}</div>
        </body>
      </html>
    `);
    popup.document.close();
    popup.focus();
    popup.addEventListener("load", () => popup.print(), { once: true });
    setExportMessage("PDF print dialog opened.");
  };

  useEffect(() => {
    fitToScreen();
  }, [fitToScreen, selectedPersonId, relationships.length, isModalOpen]);

  const onViewportPointerDown = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (event.button !== 0) {
      return;
    }

    const element = event.target as HTMLElement;
    if (element.closest("button, a, select, input, textarea, label")) {
      return;
    }

    event.currentTarget.setPointerCapture(event.pointerId);
    setDragState({
      pointerId: event.pointerId,
      startX: event.clientX,
      startY: event.clientY,
      startPanX: pan.x,
      startPanY: pan.y,
    });
  };

  const onViewportPointerMove = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!dragState || dragState.pointerId !== event.pointerId) {
      return;
    }

    const nextX = dragState.startPanX + (event.clientX - dragState.startX);
    const nextY = dragState.startPanY + (event.clientY - dragState.startY);
    setPan({ x: nextX, y: nextY });
  };

  const onViewportPointerUp = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!dragState || dragState.pointerId !== event.pointerId) {
      return;
    }

    event.currentTarget.releasePointerCapture(event.pointerId);
    setDragState(null);
  };

  const renderNode = (person: Person, node: TreeNode) => (
    <div
      key={person.id}
      className={`${styles.treeNode} ${styles.treeNodeLinked} ${selectedPersonId === person.id ? styles.treeNodeActive : ""}`}
    >
      <button type="button" className={styles.cardButton} onClick={() => onSelectPerson(person.id)}>
        <strong>{person.fullName}</strong>
        <span>{descriptorForNode(node)}</span>
        <span>{getGenerationLabel(person)}</span>
      </button>
      <Link className={styles.inlineLink} href={`/family-space/members/${person.id}`}>
        View profile
      </Link>
    </div>
  );

  const renderBand = (level: number, levelNodes: Array<{ person: Person; node: TreeNode }>) => (
    <section key={level} className={styles.treeBand}>
      <div className={styles.treeBandHeader}>{rowLabel(level)}</div>
      <div className={styles.treeBandConnector}>
        <span className={styles.treeBandStem} />
        {levelNodes.length > 1 ? (
          <span
            className={styles.treeBandBranch}
            style={{ "--tree-branch-span": levelNodes.length } as CSSProperties}
          />
        ) : null}
      </div>
      <div className={`${styles.treeBandBody} ${styles.treeBandBodyConnected}`}>
        {levelNodes.map(({ person, node }) => renderNode(person, node))}
      </div>
    </section>
  );

  const renderTreeCanvas = () => (
    <div className={styles.relationshipTree}>
      {treeNodes.size > 1 || selectedPerson ? (
        <div
          ref={viewportRef}
          className={`${styles.treeViewport} ${dragState ? styles.treeViewportDragging : ""}`}
          onPointerDown={onViewportPointerDown}
          onPointerMove={onViewportPointerMove}
          onPointerUp={onViewportPointerUp}
          onPointerCancel={onViewportPointerUp}
        >
          <div
            ref={canvasRef}
            className={styles.treeCanvasInteractive}
            style={{
              transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
            }}
          >
            <div className={styles.treeCanvas}>
              {groupedLevels.above.map(([level, levelNodes]) => renderBand(level, levelNodes))}

              {groupedLevels.above.length ? (
                <div className={styles.treeFocusConnector}>
                  <span className={styles.treeFocusStem} />
                </div>
              ) : null}

              {selectedPerson ? (
                <div className={styles.focusPairRow}>
                  <div className={styles.focusNode}>
                    <strong>{selectedPerson.fullName}</strong>
                    <span>{partnerRoleLabel(selectedPerson.gender)}</span>
                    <span>{getGenerationLabel(selectedPerson)}</span>
                  </div>
                  {primarySpouse ? (
                    <>
                      <span className={styles.focusPairJoin}>+</span>
                      <div className={`${styles.focusNode} ${styles.focusNodeSecondary}`}>
                        <button type="button" className={styles.cardButton} onClick={() => onSelectPerson(primarySpouse.id)}>
                          <strong>{primarySpouse.fullName}</strong>
                          <span>{partnerRoleLabel(primarySpouse.gender)}</span>
                          <span>{getGenerationLabel(primarySpouse)}</span>
                        </button>
                      </div>
                    </>
                  ) : null}
                </div>
              ) : (
                <div className={styles.focusNode}>
                  <strong>Select a member</strong>
                  <span>Choose someone from the directory to see their family links.</span>
                </div>
              )}

              {sameGenerationSiblings.length || groupedLevels.below.length ? (
                <div className={styles.treeFocusConnector}>
                  <span className={styles.treeFocusStem} />
                </div>
              ) : null}

              {sameGenerationSiblings.length ? (
                <section className={styles.treeBand}>
                  <div className={styles.treeBandHeader}>Siblings</div>
                  <div className={`${styles.treeBandBody} ${styles.treeSiblingRow}`}>
                    {sameGenerationSiblings.map(({ person, node }) => renderNode(person, node))}
                  </div>
                </section>
              ) : null}

              {groupedLevels.below.map(([level, levelNodes]) => renderBand(level, levelNodes))}
            </div>
          </div>
        </div>
      ) : (
        <div className={styles.treeEmpty}>
          No explicit relationships are linked to this member yet. Add spouse or kid links to grow the tree.
        </div>
      )}
    </div>
  );

  return (
    <>
    <section className={`${styles.panel} ${styles.treePanel}`}>
      <div className={styles.treeCta}>
        <div>
          <p className={styles.treeCtaLabel}>Relationship Tree</p>
          <h2 className={styles.treeCtaTitle}>View family links by generation</h2>
          <p className={styles.treeCtaSub}>
            {memberCount ?? people.length} members - {relationshipCount ?? relationships.length} relationships
            {selectedPerson ? ` - centered on ${selectedPerson.fullName}` : ""}
          </p>
          <div className={styles.treeCtaActions}>
            <button type="button" className={styles.heroGhostButton} onClick={() => setIsModalOpen(true)}>
              Open Full Screen Tree
            </button>
          </div>
        </div>
      </div>
    </section>

      {isModalOpen ? (
        <div className={styles.treeModalOverlay} role="dialog" aria-modal="true" aria-label="Relationship Tree">
          <section className={`${styles.panel} ${styles.treePanel} ${styles.treePanelFullscreen}`}>
            <button
              type="button"
              aria-label="Close Relationship Tree"
              className={styles.treeModalClose}
              onClick={() => setIsModalOpen(false)}
            >
              x
            </button>

            <div className={styles.panelHeader}>
              <h2>Relationship Tree</h2>
              <p>
                View family links by generation around the selected person.
                {memberCount || relationshipCount
                  ? ` ${memberCount ?? people.length} members - ${relationshipCount ?? relationships.length} relationships`
                  : ""}
              </p>
            </div>

            <div className={styles.treeToolbar}>
              <div className={styles.treeZoomGroup}>
                <button
                  type="button"
                  className={styles.secondaryButton}
                  onClick={() => applyZoomAroundCenter(zoom - ZOOM_STEP)}
                >
                  Zoom Out
                </button>
                <button type="button" className={styles.secondaryButton} onClick={() => applyZoomAroundCenter(1)}>
                  {Math.round(zoom * 100)}%
                </button>
                <button
                  type="button"
                  className={styles.secondaryButton}
                  onClick={() => applyZoomAroundCenter(zoom + ZOOM_STEP)}
                >
                  Zoom In
                </button>
              </div>

              <button type="button" className={styles.secondaryButton} onClick={fitToScreen}>
                Fit to Screen
              </button>
              <button type="button" className={styles.secondaryButton} onClick={exportImage}>
                Export Image
              </button>
              <button type="button" className={styles.secondaryButton} onClick={exportPdf}>
                Export PDF
              </button>
            </div>

            {exportMessage ? <p className={styles.inlineStatus}>{exportMessage}</p> : null}
            {renderTreeCanvas()}
          </section>
        </div>
      ) : null}
    </>
  );
}
